// DeleteResourcePool removes a pool, returning its id and name for the toast.
func (r *mutationResolver) DeleteResourcePool(ctx context.Context, id string) (*model.DeleteResourcePoolPayload, error) {
	pid, err := uuid.Parse(id)
	if err != nil {
		return nil, gqlerror.Errorf("invalid id")
	}
	p, err := r.Ent.ResourcePool.Get(ctx, pid)
	if err != nil {
		return nil, err
	}
	// resource_pool_id is a soft reference (no FK). Refuse to orphan agents whose
	// VMs live in this pool — RecycleAgent/sync resolve the VM via its pool, so a
	// dangling reference would silently break them.
	if n, err := r.Ent.Agent.Query().Where(agent.ResourcePoolID(pid)).Count(ctx); err != nil {
		return nil, err
	} else if n > 0 {
		return nil, gqlerror.Errorf("resource pool is used by %d agent(s); recycle or reassign them first", n)
	}
	if err := r.Ent.ResourcePool.DeleteOneID(pid).Exec(ctx); err != nil {
		return nil, err
	}
	r.audit(ctx, "resource_pool.delete", "resource_pool", id, true, actorID(auth.FromContext(ctx)))
	return &model.DeleteResourcePoolPayload{ID: id, DeletedName: p.Name}, nil
}

// TestResourcePoolConnection is the 接入表单 pre-save probe. It has two modes:
//
//   - Credential-less (no username/password): a lightweight reachability check —
//     the endpoint is well-formed and the vCenter HTTPS port is dial-reachable
//     (TCP). vSphereVersion/itemCount stay empty, contentLibraryFound=false.
//   - Authenticated (credentials supplied): a REAL govmomi login that reads the
//     vSphere version and verifies the content library exists + counts its items —
//     catching a bad credential or a typo'd contentLibraryName at form time
//     instead of at deploy. Credentials are used only for this probe.
//
// A pool row is NEVER created or mutated here. Raw network/auth errors are logged
// server-side but never echoed (they can leak internal topology — this is a
// payload field, so it bypasses the GraphQL ErrorPresenter).
func (r *mutationResolver) TestResourcePoolConnection(ctx context.Context, input model.TestResourcePoolConnectionInput) (*model.ResourcePoolConnectionTest, error) {
	actor := actorID(auth.FromContext(ctx))
	username, password := derefString(input.Username), derefString(input.Password)

	// --- Credential-less reachability path (backward compatible) ---
	if username == "" && password == "" {
		host, err := parseEndpointHostPort(input.Endpoint)
		if err != nil {
			r.audit(ctx, "resource_pool.test", "resource_pool", input.Name, false, actor)
			return &model.ResourcePoolConnectionTest{Ok: false, Message: err.Error()}, nil
		}
		if derr := dialReachable(ctx, host); derr != nil {
			r.audit(ctx, "resource_pool.test", "resource_pool", input.Name, false, actor)
			log.Printf("resource pool test: %q not reachable: %v", host, derr)
			return &model.ResourcePoolConnectionTest{Ok: false, Message: "endpoint is not reachable"}, nil
		}
		r.audit(ctx, "resource_pool.test", "resource_pool", input.Name, true, actor)
		return &model.ResourcePoolConnectionTest{
			Ok:      true,
			Message: fmt.Sprintf("%s is reachable (no credentials given — content libraries not fetched)", host),
			Detail:  &model.ResourcePoolConnectionDetail{VSphereVersion: "", ContentLibraries: []string{}},
		}, nil
	}

	// --- Authenticated probe path ---
	if r.VCenterConnect == nil {
		return &model.ResourcePoolConnectionTest{Ok: false, Message: "vCenter access is not configured on this server"}, nil
	}
	insecure := input.Insecure != nil && *input.Insecure
	conn, err := r.VCenterConnect(ctx, input.Endpoint, username, password, insecure)
	if err != nil {
		r.audit(ctx, "resource_pool.test", "resource_pool", input.Name, false, actor)
		log.Printf("resource pool test: connect %q failed: %v", input.Name, err)
		return &model.ResourcePoolConnectionTest{Ok: false, Message: "vCenter connection or authentication failed"}, nil
	}
	defer func() { _ = conn.Logout(ctx) }()

	about := conn.About()
	libs, err := conn.ListContentLibraries(ctx)
	if err != nil {
		r.audit(ctx, "resource_pool.test", "resource_pool", input.Name, false, actor)
		log.Printf("resource pool test: list libraries for %q failed: %v", input.Name, err)
		return &model.ResourcePoolConnectionTest{
			Ok:      false,
			Message: "connected, but the content-library list request failed",
			Detail:  &model.ResourcePoolConnectionDetail{VSphereVersion: about.Version, ContentLibraries: []string{}},
		}, nil
	}
	r.audit(ctx, "resource_pool.test", "resource_pool", input.Name, true, actor)
	return &model.ResourcePoolConnectionTest{
		Ok:      true,
		Message: fmt.Sprintf("connected (vSphere %s); found %d content library(s)", about.Version, len(libs)),
		Detail:  &model.ResourcePoolConnectionDetail{VSphereVersion: about.Version, ContentLibraries: libs},
	}, nil
}

// SyncResourcePool dials the pool, counts inventory, and persists it (同步数据).
func (r *mutationResolver) SyncResourcePool(ctx context.Context, id string) (*model.SyncResourcePoolPayload, error) {
	pid, err := uuid.Parse(id)
	if err != nil {
		return nil, gqlerror.Errorf("invalid id")
	}
	pool, err := r.Ent.ResourcePool.Get(ctx, pid)
	if err != nil {
		return nil, err
	}
	conn, err := r.connectPool(ctx, pool)
	if err != nil {
		_, _ = r.Ent.ResourcePool.UpdateOne(pool).SetStatus(resourcepool.StatusError).Save(ctx)
		return nil, fmt.Errorf("connect: %w", err)
	}
	defer func() { _ = conn.Logout(ctx) }()
	inv, err := conn.Inventory(ctx)
	if err != nil {
		return nil, fmt.Errorf("inventory: %w", err)
	}
	now := time.Now()
	pool, err = r.Ent.ResourcePool.UpdateOne(pool).
		SetStatus(resourcepool.StatusConnected).
		SetDatacenterCount(inv.Datacenters).
		SetClusterCount(inv.Clusters).
		SetHostCount(inv.Hosts).
		SetVMCount(inv.VMs).
		SetLastSyncedAt(now). // real inventory-sync time → drives syncStatus/lastSyncedAt
		Save(ctx)
	if err != nil {
		return nil, err
	}
	r.audit(ctx, "resource_pool.sync", "resource_pool", id, true, actorID(auth.FromContext(ctx)))
	return &model.SyncResourcePoolPayload{Pool: toModelResourcePool(pool), SyncedAt: now}, nil
}

// ResourcePools is a filtered/sorted/paged connection of pools (console 资源池 page).
func (r *queryResolver) ResourcePools(ctx context.Context, filter *model.ResourcePoolFilter, pagination *model.Pagination, sort *model.ResourcePoolSort) (*model.ResourcePoolConnection, error) {
	base := r.Ent.ResourcePool.Query()
	if filter != nil {
		if v := derefString(filter.NameKeyword); v != "" {
			base = base.Where(resourcepool.NameContainsFold(v))
		}
		if v := derefString(filter.EndpointKeyword); v != "" {
			base = base.Where(resourcepool.EndpointContainsFold(v))
		}
		if filter.ConnectionStatus != nil {
			// Binary console status → ent tri-state: CONNECTED == connected;
			// DISCONNECTED covers both disconnected and error.
			if *filter.ConnectionStatus == model.PoolConnectionStatusConnected {
				base = base.Where(resourcepool.StatusEQ(resourcepool.StatusConnected))
			} else {
				base = base.Where(resourcepool.StatusIn(resourcepool.StatusDisconnected, resourcepool.StatusError))
			}
		}
	}
	total, err := base.Clone().Count(ctx)
	if err != nil {
		return nil, err
	}
	page, pageSize := 1, 20
	if pagination != nil {
		if pagination.Page > 0 {
			page = pagination.Page
		}
		if pagination.PageSize > 0 {
			pageSize = pagination.PageSize
		}
	}
	pools, err := applyResourcePoolSort(base.Clone(), sort).Offset((page - 1) * pageSize).Limit(pageSize).All(ctx)
	if err != nil {
		return nil, err
	}
	nodes := make([]model.ResourcePool, 0, len(pools))
	for _, p := range pools {
		nodes = append(nodes, *toModelResourcePool(p))
	}
	totalPages := (total + pageSize - 1) / pageSize
	return &model.ResourcePoolConnection{
		Nodes:      nodes,
		TotalCount: total,
		PageInfo:   &model.PageInfo{Page: page, PageSize: pageSize, TotalPages: totalPages},
	}, nil
}

